const input = $input.item.json;
const { campos, total, topMunicipios, topOrgaos, topTipos, qtdAndamento, qtdConcluido, investimentoTotal } = input;

const preenchidos = Object.entries(campos || {})
  .filter(([k, v]) => v && v !== 'QUALQUER')
  .map(([k, v]) => `${k}: ${v}`)
  .join(', ');

let contextoBusca = preenchidos ? `Filtros já aplicados: ${preenchidos}. ` : 'Sem filtros definidos ainda. ';
contextoBusca += `A busca retornou ${total} projetos. `;

// Município: só lista quando há mais de 1 opção
if (topMunicipios && topMunicipios.length > 1) {
  const listaMunicipios = topMunicipios.slice(0, 10).map(([m, q]) => `${m} (${q} projeto${q > 1 ? 's' : ''})`).join(', ');
  const totalMunicipios = topMunicipios.length;
  contextoBusca += `Municípios com mais projetos (${totalMunicipios} no total): ${listaMunicipios}. `;
}

// Situação: só oferece como filtro quando há projetos nos dois estados; menu sempre numerado
const temVariedadeSituacao = qtdAndamento > 0 && qtdConcluido > 0;
if (temVariedadeSituacao) {
  contextoBusca += `Situação dos projetos — use EXATAMENTE este menu numerado (um por linha):\n1 Em andamento\n2 Concluídos\n`;
}

// Órgão: só lista quando há mais de 1 opção (filtrar faz sentido)
if (topOrgaos && topOrgaos.length > 1) {
  const listaOrgaos = topOrgaos.slice(0, 5).map(([o, q], i) => `${i + 1} ${o}`).join('\n');
  contextoBusca += `Órgãos disponíveis (use menu numerado):\n${listaOrgaos}\n`;
}

// Tipo: só lista quando há mais de 1 opção
if (topTipos && topTipos.length > 1) {
  const listaTipos = topTipos.slice(0, 4).map(([t, q], i) => `${i + 1} ${t}`).join('\n');
  contextoBusca += `Tipos disponíveis (use menu numerado):\n${listaTipos}\n`;
}

if (investimentoTotal) {
  contextoBusca += `Investimento total: ${investimentoTotal}. `;
}

const campos_ignorados = Object.entries(campos || {})
  .filter(([k, v]) => v === 'QUALQUER')
  .map(([k]) => k);

if (campos_ignorados.length) {
  contextoBusca += `Campos que o usuário não sabe (NÃO perguntar sobre estes): ${campos_ignorados.join(', ')}. `;
}

// Só sugere campos que têm múltiplas opções reais para filtrar
const camposFiltraveleis = {
  municipio: topMunicipios && topMunicipios.length > 1,
  situacao: temVariedadeSituacao,
  orgao: topOrgaos && topOrgaos.length > 1,
  tipo: topTipos && topTipos.length > 1,
  nome: true
};

const campos_faltantes = ['municipio', 'situacao', 'orgao', 'tipo', 'nome']
