const groqResp = $input.item.json;
const prep = $('PreparaGroqClassificador').first().json;
const remetente = prep.remetente;
const buscaLimpa = prep.busca_limpa;
const camposAcumulados = prep.campos_acumulados || {};
const projetoAtual = prep.projeto_atual;

const staticData = $getWorkflowStaticData('global');
if (!staticData.contextos) staticData.contextos = {};
let contexto = staticData.contextos[remetente] || { termos: [], lista: null, contratos: null, campos_acumulados: {}, projeto_exibido: false, projeto_atual: null, ultimaInteracao: null };
const agora = Date.now();

let classificacao = { tipo: 'busca' };
try {
  const texto = groqResp.choices[0].message.content.trim();
  classificacao = JSON.parse(texto.replace(/```json|```/g, '').trim());
} catch(e) {}

const tipo = classificacao.tipo;

if (tipo === 'saudacao') {
  staticData.contextos[remetente] = { termos: [], lista: null, contratos: null, campos_acumulados: {}, projeto_exibido: false, projeto_atual: null, ultimaInteracao: agora };
  return [{ tipo: 'saudacao', busca_limpa: '', remetente, mensagem_retorno: '' }];
}

if (tipo === 'reinicio') {
  staticData.contextos[remetente] = { termos: [], lista: null, contratos: null, campos_acumulados: {}, projeto_exibido: false, projeto_atual: null, ultimaInteracao: agora };
  return [{ tipo: 'reinicio', busca_limpa: '', remetente, mensagem_retorno: '' }];
}

if (tipo === 'submenu_entregas') {
  contexto.ultimaInteracao = agora;
  staticData.contextos[remetente] = contexto;
  return [{ tipo: 'submenu', submenu: 'entregas', projeto: projetoAtual, busca_limpa: '', remetente, mensagem_retorno: '' }];
}

if (tipo === 'submenu_valores') {
  contexto.ultimaInteracao = agora;
  staticData.contextos[remetente] = contexto;
  return [{ tipo: 'submenu', submenu: 'valores', projeto: projetoAtual, busca_limpa: '', remetente, mensagem_retorno: '' }];
}

if (tipo === 'submenu_contratos') {
  contexto.ultimaInteracao = agora;
  contexto.contratos = null;
  staticData.contextos[remetente] = contexto;
  return [{ tipo: 'submenu', submenu: 'contratos', projeto: projetoAtual, busca_limpa: '', remetente, mensagem_retorno: '' }];
}

if (tipo === 'pergunta_livre') {
  contexto.ultimaInteracao = agora;
  staticData.contextos[remetente] = contexto;
  return [{ tipo: 'pergunta_livre', pergunta: buscaLimpa, projeto_atual: projetoAtual || null, remetente, mensagem_retorno: '' }];
}

if (tipo === 'pular_campo') {
  const campos = { ...camposAcumulados };
  if (!campos.municipio) campos.municipio = 'QUALQUER';
  else if (!campos.situacao) campos.situacao = 'QUALQUER';
  else if (!campos.nome) campos.nome = 'QUALQUER';
  else if (!campos.orgao) campos.orgao = 'QUALQUER';
  else if (!campos.tipo) campos.tipo = 'QUALQUER';
  contexto.campos_acumulados = campos;
  contexto.ultimaInteracao = agora;
  staticData.contextos[remetente] = contexto;
  return [{ tipo: 'busca', busca_limpa: 'refinar', campos_acumulados: campos, campos_faltantes: [], remetente, mensagem_retorno: '' }];
}

// BUSCA (default)
const camposNovos = classificacao.campos || {};
const campos = contexto.projeto_exibido ? {} : { ...camposAcumulados };
Object.keys(camposNovos).forEach(key => {
  if (campos[key] !== 'QUALQUER') campos[key] = camposNovos[key];
});

contexto.campos_acumulados = campos;
contexto.projeto_exibido = false;
contexto.ultimaInteracao = agora;
staticData.contextos[remetente] = contexto;

const campos_faltantes = ['municipio', 'situacao', 'nome', 'orgao', 'tipo'].filter(k => !campos[k]);
const busca_limpa_completa = [campos.nome, campos.municipio, campos.situacao, campos.tipo, campos.orgao]
  .filter(v => v && v !== 'QUALQUER').join(' ') || buscaLimpa;

return [{ tipo: 'busca', busca_limpa: busca_limpa_completa, campos_acumulados: campos, campos_faltantes, remetente, mensagem_retorno: '' }];
